const Redis = require('ioredis');
const pub = new Redis(), sub = new Redis();
const adapter = {
    publish:   (ch, msg) => pub.publish(ch, JSON.stringify(msg)),
    subscribe: (ch, cb) => {
        sub.subscribe(ch);
        const on = (c, raw) => { if (c === ch) cb(JSON.parse(raw)); };
        sub.on('message', on);
        return () => { sub.off('message', on); sub.unsubscribe(ch); };
    },
};
